var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"괴, 굉장해요……!","JPN":"す、すごい……！","ENG":"A-amazing...!","TWN":"真，真是難以置信……！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L6_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"밖에서 봤을 때는 무너져가는 유적이었는데 내부는 멀쩡하네요.","JPN":"外観は崩れかけの遺跡だったけど、内部はきれいなんですね。","ENG":"From outside it looked like a crumbling ruin, but the inside is intact.","TWN":"外面看起來是個破舊的遺跡，可內部卻很正常呢。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L7_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"생각했던 것보다는 좀 평범한데?","JPN":"思ったより普通やな。","ENG":"Kind of plain, isn't it?","TWN":"比我想像中要普通一些呢？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"내는 황금향 유적이라카면, 삐까번쩍할 줄 알았거든?","JPN":"黄金郷の遺跡っちゅうから、ウチはもっと派手なもんやと思ててん。","ENG":"When I heard Golden Vale ruins, I expected something flashy.","TWN":"我還以為黃金城遺跡會金光閃閃？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"아니, 유심히 보게나. 인디애나 GAP.","JPN":"いや、よく見るんじゃ、インディアナ-甲-。","ENG":"Look closer, Indiana G.A.P.","TWN":"不，你仔細看看，印第安納GAP。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L11_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"유적에 황금향 이끼가 잔뜩 끼어 있어. 분명, 누군가의 피가 닿으면 금빛으로 변할 걸세.","JPN":"遺跡に黄金郷の苔がたくさん生えておる。きっと、誰かの血に触れると金色に変わるじゃろう。","ENG":"The walls are covered in Golden Vale moss. If touched with blood, it will gleam gold.","TWN":"遺跡上滿是黃金城苔蘚。肯定沒錯，如果沾上某人的血液，就會變成金色。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"평생을 황금향의 전설을 연구하는데 바쳤어.","JPN":"ワシは黄金郷の伝説の研究に生涯を捧げた。","ENG":"I devoted my life to studying the legend of the Golden Vale.","TWN":"我一生都致力於研究黃金城的傳說。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그런 이 몸이 보증하지. 이곳은 틀림없는 전설 속의 황금향 유적이야.","JPN":"そのワシが保証しよう。ここは紛れもなく、伝説にある黄金郷の遺跡じゃ。","ENG":"I vouch for it. This is truly the legendary Golden Vale ruin.","TWN":"我可以保證，這裡無疑就是傳說中的黃金城遺跡。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"하지만 대체 이건……?","JPN":"しかし、これはいったい……？","ENG":"But what in the world is this...?","TWN":"但這到底是……？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"도착했어요.","JPN":"着きました。","ENG":"We've arrived.","TWN":"到了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L22_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"이, 이터니움이에요! 이렇게 많은 양은 처음 봐요!","JPN":"エ、エタニウムです！　こんなに大量のエタニウムは初めて見ます！","ENG":"I-it's Eternium! I've never seen this much before!","TWN":"這，這是永恆之晶！我從來沒見過這麼多！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_03"},{"id":"L23_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"우와, 고급스러운 물건들이 잔뜩 있어요! 어디에 쓰는 물건일까요?","JPN":"うわあ、高級そうな物がたくさん……！　どこに使う物なんでしょう？","ENG":"Wow, all these luxurious relics! What could they be used for?","TWN":"哇，這裡有好多高級的東西！這些東西是用來做什麼的呢？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"마, 로빈아. 함부로 막 건들지 마라. 뭔가 쌔하다 이거.","JPN":"ロビン、不用意に触れたらあかん。嫌な予感がする。","ENG":"Robin, don't touch anything. Something doesn't feel right.","TWN":"喂，蘿蘋。別隨便亂碰。這東西有點不對勁。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"네? 무슨 말씀이세요?","JPN":"え？　どういうことですか？","ENG":"Huh? What do you mean?","TWN":"嗯？什麼意思？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"영감님은 이 공간에서 뭔가 위화감 같은 거 못 느꼈습니까?","JPN":"じじいはこの空間で何か違和感、感じんかった？","ENG":"Old man, don't you feel something off about this place?","TWN":"你不覺得這個空間有些不對勁嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"자네도 느꼈군. 나도 이상하다고 생각하던 참이었네.","JPN":"おぬしも感づいていたか。ワシもおかしいと思っていたところじゃ。","ENG":"You feel it too. I was thinking the same.","TWN":"你也有感覺到嗎？我也正覺得奇怪呢。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"관리국 표준 매뉴얼에 따르면, 이터니움은 한 장소에 보관할 수 있는 양이 정해져 있네.","JPN":"管理局の標準マニュアルによると、1か所に保管できるエタニウムの量は限られておる。","ENG":"According to Administration protocol, there's a strict limit on how much Eternium can be stored in one place.","TWN":"根據管理局手冊，永恆之晶在一個地方的存放量是有限制的。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"많은 양의 이터니움이 한 곳에 모여 있으면, 차원 계면을 융해시켜 버리거든.","JPN":"大量のエタニウムが1か所に集まっていると、次元界面を融解させてしまうからのう。","ENG":"Too much Eternium dissolves the dimension surface.","TWN":"大量的永恆之晶聚集在一起，會融化次元介面。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"저 정도 양이라면, 진작에 차원 자체가 녹아뿌렸겠지예.","JPN":"あの量ならとっくに次元ごと溶けてたはずやで。","ENG":"With this much, the dimension should've melted down already.","TWN":"如果是這種程度的量，次元本身應該早就瓦解了吧。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L34_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"뭔가가 억지로 이 유적이 있는 공간을 붙들어 매고 있는 게 틀림없습니다.","JPN":"間違いない。何かが、この遺跡が存在する空間を無理やり留めてるんや。","ENG":"Something must be forcibly holding this ruin in place.","TWN":"一定有什麼東西強行將遺跡所在的空間固定住。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L35_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"그, 그렇게 말씀하시니까 뭔가 으스스한데요?","JPN":"そ、そう言われると何だかゾッとします。","ENG":"N-now that you say that, it feels eerie...","TWN":"你，你這麼說讓我有點心裡毛毛欸？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"니 말이 맞다. 으스스하지.","JPN":"ゾットする……その通りや。","ENG":"Exactly. Eerie.","TWN":"你說的沒錯。真是毛毛的。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"왠지 들어올 때부터 쌔했다. 마치 공간 자체에 누군가의 의지가 있는 것처럼…….","JPN":"入ってきた時からそうやった。空間そのものに誰かの意志があるような……","ENG":"It's felt wrong since we walked in, like someone's will is bound to the space itself...","TWN":"從進來的時候我就感覺有些不對勁，感覺空間本身有某種意志一樣……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그래, 꼭 카운터의 CRF와 비슷한 기운이라고 할까……?","JPN":"せやな、まるでカウンターのCRFに似ている気配や。","ENG":"It feels almost like a Counter's CRF...","TWN":"沒錯，和制裁者的CRF很類似……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"맞아요.","JPN":"そうです。","ENG":"That's right.","TWN":"沒錯。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"맞아요. 원래라면 이 유적은 존재할 수 없거든요.","JPN":"そうです。本来ならこの遺跡は存在できません。","ENG":"\\"That's right. Normally, this ruin couldn't exist at all.\\"","TWN":"沒錯。按理說，這個遺跡本不該存在。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"한 사람의 의지가 아주 오랫동안 이 유적을 유지시키고 있는 거죠.","JPN":"1人の意志が、長い間この遺跡を維持しているんです。","ENG":"\\"One person's will has been preserving it all this time.\\"","TWN":"是一個人的意志長時間維持著這片遺跡。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"먼 훗날, 이 유적을 찾아낼 누군가를 간절히 기다리면서.","JPN":"遠い未来、この遺跡を見つけ出してくれる誰かを、待ち望んで。","ENG":"\\"Waiting desperately for someone to finally find it.\\"","TWN":"熱切地等待著未來有人能找到這處遺跡。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"그리고 그 분이 저를 이곳으로 이끄셨어요.","JPN":"そして、その人が私をここへと導きました。","ENG":"\\"And that person guided me here.\\"","TWN":"而且是他把我引導到這裡來的。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"……라고 시타 아가씨께서는 쓸쓸하게 답하십니다.","JPN":"……と、シータお嬢様が寂しげにおっしゃっています。","ENG":"...is what Lady Sita says, her voice tinging with sorrow.","TWN":"……悉多小姐如此說道。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"유적을 지키고 있는 사람이 있다고요?","JPN":"遺跡を守っている人がいる？","ENG":"You're saying someone's guarding this ruin?","TWN":"有人在看守遺跡嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"에이, 그럴 리가 없지예. 여긴 이면세계 유적입니다. 사람은 살 수가 없어요.","JPN":"いや、そんなはずはない。ここは裏世界の遺跡やで。人間が住める場所やない。","ENG":"No way. This is a Counterside ruin. No human could live here.","TWN":"哎呀，不可能的。這是異界遺跡，人類無法生存。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그 말이 진짜라카면, 그 사람은 지금 어디 있는 겁니까?","JPN":"それに、それが本当なら、その人は今どこにいるんや？","ENG":"If that's true, then where is this \\"someone\\"?","TWN":"如果那話是真的，那個人現在在哪？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"그 분은…….","JPN":"その方は……","ENG":"That person is...","TWN":"他……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시, 시타 아가씨? 그게 무슨 뜻이죠?","JPN":"シ、シータお嬢様？　どういう意味ですか？","ENG":"L-Lady Sita? What do you mean?","TWN":"悉多小姐？這是什麼意思？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"그 분은… 여러분의 발 밑에 있어요…….","JPN":"その方は……皆さんの足元にいます……","ENG":"That person is right beneath your feet.","TWN":"他……就在你們腳下……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"발 밑이라고요……","JPN":"足元……","ENG":"Beneath our... feet?","TWN":"腳下……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"헙!?","JPN":"はっ！？","ENG":"Huh?!","TWN":"嚇！？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L11_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"이거… 해골 아이가……?","JPN":"これは……骸骨やないか……？","ENG":"Is that... a skeleton...?","TWN":"這個……是骷髏嗎……？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L12_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"지금 이게 유적을 지켜주고 있다고요……?","JPN":"これが、遺跡を守っている……？","ENG":"This skeleton is what's been guarding the ruin...?","TWN":"就是這個東西在保護遺跡嗎……？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그렇군…….","JPN":"そうか……","ENG":"I see now...","TWN":"原來如此……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"이제야 모든 걸 알 것 같네.","JPN":"ようやくすべてが分かった気がするのう。","ENG":"At last, everything makes sense.","TWN":"我現在明白了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"칸 영감님……?","JPN":"じじい……？","ENG":"Old man Khan...?","TWN":"坎老頭……？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"아마도 그건 오래전, 이 유적을 지키던 누군가의 유해일 걸세.","JPN":"おそらくそれは遠い昔、この遺跡を守っていた誰かの遺骸じゃろう。","ENG":"It must be the remains of one who once protected this place.","TWN":"也許那是很久以前，守護這遺跡的某個人的遺骸吧。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그리고 죽어서까지도 그 의지가 유해에 남아, 이 공간을 유지하고 있는 것이라네.","JPN":"息が絶えてもその意志は遺骸に宿り、この空間を保ってくれているのじゃ。","ENG":"Even in death, their will lingered in their remains, sustaining this space.","TWN":"而且即使死後，那份意志仍然留在遺體中，維持著這個空間。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그 의지는, 가능성을 현실로 바꾸는 힘…….","JPN":"その意志は、可能性を現実に変える力……","ENG":"That will... a force that makes possibility into reality.","TWN":"那意志，是將可能性變為現實的力量……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L20_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그래. 이를테면, 그건 카운터의 CRF와 같다고 할 수 있겠군.","JPN":"そうじゃな、カウンターのCRFのようなものだと言えるじゃろう。","ENG":"Yes. Much like a Counter's CRF.","TWN":"是的，可以說就像是制裁者的CRF。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L23_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그럼, 이 유해의 주인은 죽은 뒤에도 카운터 능력을 유지하고 있다는 겁니까?","JPN":"じゃ、この遺骸の主は死んだ後もカウンターの能力を持っとるんか？","ENG":"Then this person kept their Counter ability even in death?","TWN":"那麼，這具遺骸的主人在死後仍然保持著制裁者的能力嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"유해에서 방출되는 CRF가 이 공간을 유지하고 있다고요?","JPN":"遺骸から放出されているCRFがこの空間を維持してんの？","ENG":"And that CRF is what sustains the ruin?","TWN":"從遺骸中釋放的CRF正在維持這個空間嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그래, 그런 말이 되겠지.","JPN":"ああ、そういうことになるじゃろう。","ENG":"That's right.","TWN":"對，你說得沒錯。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"특수한 침식파에 의해, 육체의 생물학적 구조가 뒤틀리며 아티팩트처럼 되면서까지…….","JPN":"特殊な侵食波によって、肉体の生物学的な構造が捻じ曲げられ、アーティファクトのようになってまで……","ENG":"The unique Corruption ray twisted its body into something Artifact-like.","TWN":"由於特殊的侵蝕波，身體的生物結構被扭曲，甚至變得像人造神器一樣……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그자는 이 유적을 포기하지 않았어. 죽어서까지 포기하지 않았지.","JPN":"その者はこの遺跡を諦めなかった。死んだ後もな。","ENG":"But even so, that person refused to let go. Not even in death.","TWN":"他沒有放棄這個遺跡，死後也沒有放棄。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"먼 훗날, 황금향의 유산을 찾아내고, 상속하게 될 후손을 위해서 말이네.","JPN":"遠い未来、黄金郷の遺産を見つけ出し、相続するであろう末裔のために。","ENG":"They preserved it for the descendant who would inherit the Golden Vale.","TWN":"是為了將來某天，能讓後世之人找到並繼承黃金城的寶藏。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"후손이라고요?","JPN":"末裔？","ENG":"A descendant?","TWN":"後世之人？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"아마존 유역 원주민들. 그리고 여전히 천공섬에 살고 있는 원주민들…….","JPN":"アマゾン流域に住んでいる、そして今も天空島に住まう先住民たち……","ENG":"The natives of the Amazon basin. And those still living on the floating islands.","TWN":"亞馬遜流域的原住民，還有依然生活在天空島的原住民……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그들의 선조가 어떤 세계의 <color=#ffd34c>엑자일러</color>일지도 모른다는 뜻일세.","JPN":"彼らの先祖が、とある世界の<color=#ffd34c>エグザイラー</color>かもしれんということじゃ。","ENG":"Their ancestors may have been <color=#ffd34c>Exiles</color> from another world.","TWN":"這表示他們的祖先可能是某個世界的<color=#ffd34c>流浪者</color>。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"아마 그들의 세계는 지금 우리가 직면한 재앙과 같은 방식으로 멸망했을지도 모르지.","JPN":"彼らの世界は、今ワシらが直面している災いと似た形で滅んでしまったのかもしれん。","ENG":"Perhaps their world fell to the same kind of disaster we now face.","TWN":"也許他們的世界也經歷過我們現在所面臨的災難，而且遭到毀滅。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그래서 황금향 전설을 통해, 우리에게 이 재앙에 대해 경고를 남긴 거야.","JPN":"じゃから黄金郷の伝説を通して、ワシらに災いへの警告を残したのじゃ。","ENG":"So they left behind the Golden Vale legend as a warning.","TWN":"所以透過才黃金城的傳說給我們留下關於這場災難的警告。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"시타, 너야말로 이 황금향의 정당한 상속자였구나.","JPN":"シータ、おぬしこそがこの黄金郷の正当な相続者だったのじゃな。","ENG":"Sita, you are the true heir of the Golden Vale.","TWN":"悉多，原來你才是這黃金城的正當繼承者。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그리고 내 역할은 그 상속자를 이곳까지 이끄는 것이었겠지…….","JPN":"そしてワシの役目は、その相続者をここに導くこと……","ENG":"And my role was to guide you here.","TWN":"而我的角色就是將那位繼承者引導到這裡……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"허허. 돌이켜 보면, 비로소 모든 것이 운명이었구나.","JPN":"ホホ。今思えば、すべては運命だったのじゃろう。","ENG":"Haha... Looking back, it was all fate.","TWN":"呵呵。回想起來，原來這一切都是命哪。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"황금향의 유산을 위해 평생을 바친 것도, 그 끝에 너를 거둘 수 있게 된 것도 말이다.","JPN":"黄金郷の遺産のために生涯を捧げたのも、その結果おぬしを引き取ることになったのもな。","ENG":"My life spent chasing the Golden Vale, all to lead me to you.","TWN":"為了黃金城的寶藏奉獻一生，還有收養你也是。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"할아버지…….","JPN":"おじいさま……","ENG":"Grandfather...","TWN":"爺爺……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_DESPAIR"}}}},{"id":"L46_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"찬란하게 빛나는 태양이… 나무뿌리에 가려, 그 빛을 잃어버리게 될 때.","JPN":"燦々と輝く太陽が……木の根に隠れ、その光を失う時。","ENG":"When the radiant sun is veiled by roots, its light fading away...","TWN":"當璀璨耀眼的陽光… 被樹根遮蔽而失去光芒之時，"},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"하늘이 갈라지며 땅과 구름이 맞닿는 곳… 어딘가 황금의 도시가 모습을 드러내고.","JPN":"天が切り裂かれ、地と雲が交わる場所……そのどこかに黄金の都市が姿を現し、","ENG":"The heavens will split open, and where earth and cloud meet, a golden city will appear.","TWN":"天空將會裂開，在大地與雲彩交會的地方… 黃金城將現身。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"그곳, 황금향이 남긴 유산이… 수많은 이들을 구하게 되리라.","JPN":"かの地、黄金郷が残した遺産が……多くの者を救うであろう。","ENG":"There, the Golden Vale's Legacy will save countless lives.","TWN":"黃金城留下的寶藏… 將拯救無數的人。  "},"stage":{"bg":"COUNTERSIDE_JUNGLE","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"할아버지 말대로… 아티팩트 하나하나에는 저마다의 역사가 담겨 있어요.","JPN":"おじいさまの言った通り……アーティファクトにはそれぞれの歴史が宿っています。","ENG":"Just as you said... every Artifact carries history.","TWN":"就像爺爺說的……每一件人造神器都有其獨特的歷史。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"하지만 앞으로 다가올 재앙으로부터 수많은 사람의 목숨을 지킬 물건이 있다면…….","JPN":"でも、迫り来る災いから多くの人の命を守れるものがあるとしたら……","ENG":"But if anything here can protect people from the coming disaster...","TWN":"要說真能從即將到來的災難中拯救無數人生命的東西……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"그건 단언코, 이 유해라고 생각해요.","JPN":"それは、この遺骸しかないと思います。","ENG":"It must be this very skeleton.","TWN":"我敢肯定，就是這個遺骸。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"틀림없이 이 유해야 말로, <color=#ffd34c>황금향의 유산</color>이에요.","JPN":"間違いなく、この遺骸が<color=#ffd34c>黄金郷の遺産</color>です。","ENG":"This skeleton is the true <color=#ffd34c>Legacy of the Golden Vale</color>.","TWN":"不會錯的，這遺骸就是<color=#ffd34c>黃金城的寶藏</color>。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"후후, 그래. 훌륭하구나. 시타.","JPN":"ふふ、ああ。見事じゃな、シータ。","ENG":"Haha... Well said, Sita.","TWN":"呵呵，很好。你真優秀，悉多。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"하핫, 제 생각도 그거랑 똑같다 아입니까!","JPN":"ははっ、ウチも同意見や！","ENG":"Haha! I was thinking the exact same thing!","TWN":"哈哈，我的想法也和你一樣！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"저, 저도 그렇게 생각해요!","JPN":"わ、私もそう思います！","ENG":"I-I agree too!","TWN":"我，我也是這麼想的！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_LAUGH"}}}},{"id":"L14_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"자, 그라믄 황금향의 유산도 챙겼겠다. 슬슬 관리국으로 복귀를……","JPN":"さてと、黄金郷の遺産も手に入れたし、そろそろ管理局に復帰……","ENG":"All right, we've got the Legacy. Time to head back to the Administration–","TWN":"好，那就帶上黃金城的寶藏回到管理局吧……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CITY_CAMPAMENTO","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"으음?","JPN":"ん？","ENG":"Hmm?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L16_1","type":"dialog","speaker":null,"text":{"JPN":"うむ……！？","ENG":"Mm...?!","TWN":"唔……！？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_CAVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_COMBAT_ALL_EARTHQUAKE_06"},{"id":"L18_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"이 땅울림은… 설마……?","JPN":"この揺れは……まさか……？","ENG":"This tremor... Is it...?","TWN":"這地面的震動是……難道……？"},"stage":{"bg":"CORRIDOR_08","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"데몰리션 웜…! 유적에 있는 이터니움에 이끌린기가……?","JPN":"デモリッションワーム……！　遺跡のエタニウムに引き寄せられたのか……？","ENG":"The Demolition Worm...! Was it drawn to the Eternium in the ruins?!","TWN":"爆破蠕蟲…！被遺跡中的永恆之晶吸引了嗎……？"},"stage":{"bg":"CORRIDOR_08","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L21_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"다들 뭐하노…! 가만있다간 우리 다 죽는다 아입니까? 빨리 나갑시다……!","JPN":"皆急げ！　ぼうーっとしてたら皆殺しや！　早よ逃げるで！","ENG":"What are you all waiting for...?! If we stay, we're dead! Let's get outta here!","TWN":"大家在幹什麼……！再這樣下去我們都會死的！快點離開這裡……！"},"stage":{"bg":"CORRIDOR_08","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"왕꿈틀이 놈들 생각보다 겁나 끈질기다 안하나!","JPN":"あの虫ども、意外としつこいんや！","ENG":"These big worms are tougher than cockroaches!","TWN":"這些大蟲子比想像中還要頑強呢！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_45"},{"id":"L29_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"소형 침식체들도 계속 따라붙고 있어요!","JPN":"小型の侵食体たちも追いかけてきています！","ENG":"Smaller C.O.s are still chasing us!","TWN":"小型侵蝕體也在不斷冒出來！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"이대로 가다간……!","JPN":"このままだと……！","ENG":"At this rate...!","TWN":"再這樣下去……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"시타 님이 가지고 있는 아티팩트가, 놈들을 계속 끌어당기고 있는 기라!","JPN":"シータさんが持ってるアーティファクトが、やつらを引き寄せておるんや！","ENG":"It's the Artifact Sita's carrying! That's what's drawing them!","TWN":"悉多手中的人造神器一直在吸引那些傢伙！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"에엣! 이럴 바에야, 차라리 확 버려뿔가……!","JPN":"ええいっ！　こうなったらいっそ捨てて……！","ENG":"Damn it! Maybe we should just ditch it...!","TWN":"哎呀！這樣的話，還不如乾脆扔掉……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"절대 안 될 말일세! 목적이 전도되지 않았나!","JPN":"それはならん！　本末転倒ではないか！","ENG":"Absolutely not! That defeats our entire purpose!","TWN":"絕對不行！那我們來這裡的目的是什麼！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"그 유해가 없다면, 결국 더 많은 사람이 죽게 될 걸세!","JPN":"その遺骸がないと、もっと多くの人が死ぬことになる！","ENG":"Without that relic, even more people will die!","TWN":"如果沒有那個遺骸，最終會有更多人死去的！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"농담 한번 해봤다 아닙니까, 농담!","JPN":"冗談や、冗談！","ENG":"I was kidding! It was a joke!","TWN":"這不就是開個玩笑唄，開玩笑啦！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_PRIDE"},"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"으음? 그런데 시타는 어디갔나……?","JPN":"うむ？　ところでシータはどこじゃ……？","ENG":"Mm? Wait... Where's Sita...?","TWN":"嗯？悉多去哪了……？"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_IDLE"},"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L43_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"……헙!","JPN":"……はっ！","ENG":"...Huh?!","TWN":"……嚇！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_BEAST_VOICE_46"},{"id":"L44_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"시타야! 어서 거기서 비켜라……!!","JPN":"シータ！　早くそこを離れろ……！！","ENG":"Sita! Get out of there...!!","TWN":"悉多！快躲開……！！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L47_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_OLD_NULL","text":{"KOREA":"커헉……!!","JPN":"がはっ……！！","ENG":"Kuh...!!","TWN":"咳……！！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_OLD_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L50_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_OFF","text":{"KOREA":"하, 할아버지……!","JPN":"お、おじいさま……！","ENG":"G-Grandfather...!","TWN":"爺爺……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_OFF","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"칸 영감님……!!","JPN":"カンのじじい……！！","ENG":"Old man Khan...!!","TWN":"坎老頭……！！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L3_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"야단났다, 이거! 여기서 발이 묶이면 다 죽는다 아이가!","JPN":"まいったな、ここで足止めされたら皆おしまいや！","ENG":"This isn't good. If we're stuck here we're finished!","TWN":"糟糕，這下麻煩了！困在這裡的話，大家都會沒命的！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"마, 로빈아! 니는 괘안나?","JPN":"ロビン！　あんたは大丈夫なんか？","ENG":"Hey, Robin! Are you okay?","TWN":"喂，蘿蘋！你沒事吧？"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS"}}}},{"id":"L7_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"명심해라! 지금 싸울 수 있는 건, 니랑 내밖에 없다!","JPN":"今戦えるのはあんたとウチだけやで！","ENG":"Remember! Right now it's just you and me who can fight!","TWN":"記住！現在能戰鬥的，只有你和我！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"일단, 여기는 내가 막아 볼 테니까, 니는……!","JPN":"とりあえずここはウチが引き止めるさかい、あんたは……！","ENG":"I'll hold them here, so you–!","TWN":"這裡交給我，你……！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS"}}}},{"id":"L9_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"아니요, 미리네 씨.","JPN":"いいえ、マリさん。","ENG":"No, Ms. Mi Rinae.","TWN":"不，宓璃奈。"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"여기서는 제가 오러화를 해서 시간을 벌게요!","JPN":"ここは私がオーラ化で時間を稼ぎます！","ENG":"I'll use Aurafication to buy time!","TWN":"我會用奧蘿化來爭取時間！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"미리네 씨는 사람들을 안전한 곳으로 대피시켜주세요.","JPN":"マリさんは皆さんを安全な場所に避難させてください。","ENG":"Please evacuate everyone to safety.","TWN":"宓璃奈，請把大家疏散到安全的地方。"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS2"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_21"},{"id":"L13_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"그 뒤에 나중에 탈출 포인트에서 합류해요.","JPN":"その後、脱出ポイントで合流しましょう。","ENG":"We'll regroup at the extraction point.","TWN":"之後我們在撤離點會合。"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"가스나, 그새 눈빛이 달라졌네!","JPN":"ったく、目つきがガラッと変わっとるやないか！","ENG":"Your eyes... they've changed!","TWN":"帥喔，你的眼神變咧！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"좋다, 어디 한 번 해보자고!","JPN":"よし、じゃあやってやるか！","ENG":"Fine then, let's do this!","TWN":"好，那就試試看吧！"},"stage":{"bg":"CITY_JUNGLE","bgm":"UI_GUILD_DUNGEON","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};